//
import { HORIZONTAL_ALIGN } from '../../../core/align-constants';
import { LegendRegistry } from '../../../legend/legend-registry';
import { $ZCG } from '../../../core/zcglobal';
import { mathMin, mathMax, noOperation } from '../../../core/zc-constants';
import { pick, parseShortHandValue, isUndefined } from '../../../utils/zcutils';
import { _legendType } from '../../../legend/legend-renderer-helpers';
import { isLegendEnabled } from '../../../legend/legend-helper';
import { getLegendAlignment } from '../../../legend/legend-utils';
import { getTextHeight } from '../../../label/font-helpers';

export function sizeCorrection(size, bound, options, chartObj) {
    if (chartObj.systemConf.legend.singleLayout) {
        return size;
    }

    let encode = 'z',
        { config } = options,
        { minSize, maxSize, title: titleConfig } = config, // user defined sizes
        legendType = _legendType(encode, options),
        renderer = LegendRegistry.get(encode, legendType),
        { maxWidth, maxHeight } = bound,
        viewOptions = config[legendType] || {},
        padding = pick(viewOptions.padding, 3),
        globalFont = chartObj.systemConf.canvas,
        // align
        legendAlign = getLegendAlignment(config),
        isHorizontal = legendAlign.layout === HORIZONTAL_ALIGN;

    if (!isLegendEnabled(config, chartObj, encode) || renderer === noOperation) {
        return size;
    }

    if (renderer.adjustFactor) {
        if (titleConfig.show) {
            let titleMargin = parseShortHandValue(pick(titleConfig.margin, 3)),
                { keepAligned } = titleConfig;

            if (!(keepAligned && isHorizontal)) {
                maxHeight -= getTextHeight([titleConfig, globalFont, $ZCG]) + titleMargin.top + titleMargin.bottom;
            }
        }

        let adjust = renderer.adjustFactor(config, maxWidth, maxHeight, globalFont, size);
        maxWidth -= adjust[0];
        maxHeight -= adjust[1];
    }

    let dim = mathMin(maxWidth, maxHeight) - 2 * padding,
        maxDim = mathMax(dim, 20), // ZC2254
        minDim = mathMax(dim * 0.1, 5);

    if (size[1] > dim) {
        if (isUndefined(maxSize)) {
            size[1] = maxDim;
        }

        if (isUndefined(minSize)) {
            size[0] = minDim;
        }
    }

    // If min size is greater than max size // DOC_BUBBLEPIE_6
    if (size[0] > size[1]) {
        if (isUndefined(maxSize)) {
            size[1] = size[0];
        }

        if (isUndefined(minSize)) {
            size[0] = size[1];
        }
    }

    return size;
}
